package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetQuoteMode_DefaultInstance() {
        CSVFormat format = CSVFormat.DEFAULT;
        QuoteMode quoteMode = format.getQuoteMode();
        assertNotNull(quoteMode);
    }

    @Test
    void testGetQuoteMode_CustomQuoteMode() throws Exception {
        QuoteMode customQuoteMode = QuoteMode.ALL;
        // Use reflection to create a CSVFormat instance with custom quoteMode,
        // since withQuoteMode(null) might not produce the expected result or the method may be final.
        CSVFormat format = CSVFormat.DEFAULT.withQuoteMode(customQuoteMode);
        assertSame(customQuoteMode, format.getQuoteMode());
    }

    @Test
    void testGetQuoteMode_NullQuoteMode() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withQuoteMode(null);
        assertNull(format.getQuoteMode());
    }
}
